$q=$pdo->prepare("SELECT c.*,a.nombre capacitacion,s.codigo seccion,i.id inscripcion_id FROM contenidos c JOIN asignaturas a ON a.id=c.asignatura_id JOIN capacitacion_secciones s ON s.id=c.seccion_id JOIN inscripciones_capacitacion i ON i.seccion_id=c.seccion_id AND i.asignatura_id=c.asignatura_id WHERE c.id=:id AND i.usuario_id=:u AND i.estado IN('inscrito','finalizado') AND c.estado='activo' AND c.activo=1 AND (c.fecha_publicacion IS NULL OR c.fecha_publicacion<=NOW())");$q->execute(['id'=>$id,'u'=>$_SESSION['usuario_id']]);$c=$q->fetch();if(!$c)mostrarPaginaErrorAtenea(403);
$pdo->prepare('INSERT INTO progreso_contenido(inscripcion_id,contenido_id,visto_at,ultima_actividad_at) VALUES(:i,:c,NOW(),NOW()) ON DUPLICATE KEY UPDATE visto_at=COALESCE(visto_at,NOW()),ultima_actividad_at=NOW()')->execute(['i'=>$c['inscripcion_id'],'c'=>$id]);$q=$pdo->prepare('SELECT * FROM entregas_contenido WHERE contenido_id=:c AND estudiante_id=:u ORDER BY intento DESC');$q->execute(['c'=>$id,'u'=>$_SESSION['usuario_id']]);$entregas=$q->fetchAll();$ultima=$entregas[0]??null;$puedeEntregar=in_array($c['tipo'],['actividad','evaluacion'],true)&&(!$ultima||in_array($ultima['estado'],['rechazada','requiere_correccion'],true));$activo=match($c['tipo']){'video'=>'videos','actividad'=>'tareas','evaluacion'=>'evaluaciones',default=>'contenidos'};$portal=portalEstudianteCabecera($c['titulo'],$activo,$c['capacitacion'].' · '.$c['seccion']);
