<div class="card"><div class="card-body"><span class="badge bg-primary"><?=atenea_e($c['modulo'])?></span> <span class="badge bg-secondary"><?=atenea_e(ucfirst($c['tipo']))?></span><h1 class="h3 mt-3"><?=atenea_e($c['titulo'])?></h1><p><?=nl2br(atenea_e((string)$c['descripcion']))?></p><?php if($c['video_url']):?><p><a class="btn btn-outline-primary" target="_blank" rel="noopener noreferrer" href="<?=atenea_e($c['video_url'])?>">Abrir video autorizado</a></p><?php endif;?><?php if($c['archivo_relpath']):?><p><a class="btn btn-outline-secondary" href="<?=atenea_url('src/academico/archivo.php?tipo=contenido&id='.(int)$c['id'])?>"><?=$c['tipo']==='video'?'Reproducir video privado':'Descargar recurso'?></a></p><?php endif;?>
<?php if(!in_array($c['tipo'],['actividad','evaluacion'],true)):?><form method="post" action="<?=atenea_url('src/estudiantes/contenido-accion.php')?>"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="completar"><input type="hidden" name="contenido_id" value="<?=$id?>"><button class="btn btn-success">Marcar como estudiado</button></form><?php elseif($puedeEntregar):?><hr><h2 class="h5">Enviar entrega</h2><form method="post" action="<?=atenea_url('src/estudiantes/contenido-accion.php')?>" enctype="multipart/form-data"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="entregar"><input type="hidden" name="contenido_id" value="<?=$id?>"><div class="mb-3"><label class="form-label" for="comentario">Comentario o explicación</label><textarea class="form-control" id="comentario" name="comentario" maxlength="5000" rows="4" required></textarea></div><div class="mb-3"><label class="form-label" for="resultado">Resultado de la práctica</label><textarea class="form-control" id="resultado" name="resultado" maxlength="10000" rows="4"></textarea></div><div class="mb-3"><label class="form-label" for="evidencias">Evidencias (máximo 5, 10 MB cada una)</label><input class="form-control" id="evidencias" type="file" name="evidencias[]" multiple accept=".pdf,.doc,.docx,.jpg,.jpeg,.png,.webp"></div><button class="btn btn-primary">Enviar para revisión</button></form><?php elseif($ultima):?><div class="alert alert-info">Última entrega: <?=atenea_e(ucfirst(str_replace('_',' ',$ultima['estado'])))?><?php if($ultima['nota']!==null):?> · Nota <?=number_format((float)$ultima['nota'],2)?>/10<?php endif;?><br><?=nl2br(atenea_e((string)$ultima['retroalimentacion']))?></div><?php endif;?>
